import{c as e,U as n,k as a,n as o}from"./chunks/framework.Cq3gzI4U.js";const y=JSON.parse('{"title":"Admin Commands","description":"","frontmatter":{},"headers":[],"relativePath":"admin-commands.md","filePath":"admin-commands.md"}'),d={name:"admin-commands.md"};function l(s,t,r,i,c,m){return n(),a("div",null,[...t[0]||(t[0]=[o('<h1 id="admin-commands" tabindex="-1">Admin Commands <a class="header-anchor" href="#admin-commands" aria-label="Permalink to “Admin Commands”">​</a></h1><p>The game uses the <strong>Cmdr</strong> execution framework. You can open the admin console at any time in-game by pressing <code>F3</code>. You can also add custom commands if you know how it works...</p><p>Below is the complete list of administrative commands combined into a single, comprehensive table. Click the section below to expand or collapse the list.</p><hr><details open><summary>📋 All Admin Commands</summary><table tabindex="0"><thead><tr><th style="text-align:left;">Command</th><th style="text-align:left;">Description</th><th style="text-align:left;">Syntax / Example</th></tr></thead><tbody><tr><td style="text-align:left;"><strong><code>AnnouncementClient</code></strong></td><td style="text-align:left;">Make an announcement for a custom player.</td><td style="text-align:left;"><code>AnnouncementClient [Player] [Message]</code></td></tr><tr><td style="text-align:left;"><strong><code>AnnouncementServer</code></strong></td><td style="text-align:left;">Make an announcement in the current server.</td><td style="text-align:left;"><code>AnnouncementServer [Message]</code></td></tr><tr><td style="text-align:left;"><strong><code>AnnouncementGlobal</code></strong></td><td style="text-align:left;">Make an announcement in all servers.</td><td style="text-align:left;"><code>AnnouncementGlobal [Message]</code></td></tr><tr><td style="text-align:left;"><strong><code>Money</code></strong></td><td style="text-align:left;">Add an amount of money to a player.</td><td style="text-align:left;"><code>Money [Player] [Amount]</code></td></tr><tr><td style="text-align:left;"><strong><code>Currency</code></strong></td><td style="text-align:left;">Add a currency to a custom path.</td><td style="text-align:left;"><code>Currency [Player] [PathTable] [Value]</code> <br> <em>Example:</em> <code>Currency Username {&quot;Rebirth&quot;} 1</code></td></tr><tr><td style="text-align:left;"><strong><code>Dice</code></strong></td><td style="text-align:left;">Give an amount of dice to a player!</td><td style="text-align:left;"><code>Dice [Player] [Name] [Amount]</code></td></tr><tr><td style="text-align:left;"><strong><code>DiceGlobal</code></strong></td><td style="text-align:left;">Give an amount of dice to all players.</td><td style="text-align:left;"><code>DiceGlobal [Name] [Amount]</code></td></tr><tr><td style="text-align:left;"><strong><code>Item</code></strong></td><td style="text-align:left;">Give an item with an optional mutation to a player.</td><td style="text-align:left;"><code>Item [Player] [ItemName] [MutationName (Optional)]</code> <br> <em>Example:</em> <code>Item Username Item A</code> <br> <em>With mutation:</em> <code>Item Username Item A Gold</code></td></tr><tr><td style="text-align:left;"><strong><code>ItemsGlobal</code></strong></td><td style="text-align:left;">Give an item to every player in the game!</td><td style="text-align:left;"><code>ItemsGlobal [ItemName] [MutationName (Optional)]</code></td></tr><tr><td style="text-align:left;"><strong><code>Event</code></strong></td><td style="text-align:left;">Start a mutation event.</td><td style="text-align:left;"><code>Event [EventName]</code></td></tr><tr><td style="text-align:left;"><strong><code>EventGlobal</code></strong></td><td style="text-align:left;">Start a mutation event in all servers.</td><td style="text-align:left;"><code>EventGlobal [EventName]</code></td></tr><tr><td style="text-align:left;"><strong><code>Gamepass</code></strong></td><td style="text-align:left;">Add a gamepass to a player.</td><td style="text-align:left;"><code>Gamepass [Player] [GamepassName]</code></td></tr><tr><td style="text-align:left;"><strong><code>Products</code></strong></td><td style="text-align:left;">Add a product to a player.</td><td style="text-align:left;"><code>Products [Player] [ProductName]</code></td></tr><tr><td style="text-align:left;"><strong><code>Ban</code></strong></td><td style="text-align:left;">Ban a player.</td><td style="text-align:left;"><code>Ban [Player] [Duration] [Reason]</code></td></tr><tr><td style="text-align:left;"><strong><code>BanId</code></strong></td><td style="text-align:left;">Ban a player using their User ID.</td><td style="text-align:left;"><code>BanId [UserId] [Duration] [Reason]</code></td></tr><tr><td style="text-align:left;"><strong><code>UnbanId</code></strong></td><td style="text-align:left;">Unban a player using their User ID.</td><td style="text-align:left;"><code>UnbanId [UserId]</code></td></tr><tr><td style="text-align:left;"><strong><code>ResetData</code></strong></td><td style="text-align:left;">Reset your data.</td><td style="text-align:left;"><code>ResetData</code></td></tr><tr><td style="text-align:left;"><strong><code>RefreshBase</code></strong></td><td style="text-align:left;">Command created just for the development of the game to reload your base when making the base system.</td><td style="text-align:left;"><code>RefreshBase</code></td></tr></tbody></table><div class="warning custom-block"><p class="custom-block-title">Rejoin Required</p><p>Rejoin after using <code>ResetData</code> to make sure everything resynces properly.</p></div></details><hr><div class="tip custom-block"><p class="custom-block-title">Auto-Completion</p><p>Don&#39;t forget that <strong>Cmdr</strong> features full auto-completion! When typing out item names, player usernames, or mutation styles, press <code>Tab</code> or look at the command suggestions right above your input line to prevent typos.</p></div>',7)])])}const f=e(d,[["render",l]]);export{y as __pageData,f as default};
